#include <stdio.h>
int main() {
    int T, N, growth_rate, max_height, days;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int plants[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &plants[i]);
        }
        max_height = 0;
        for (int i = 0; i < N; i++) {
            if (plants[i] > max_height) {
                max_height = plants[i];
            }
        }
        days = 0;
        while (1) {
            int all_same = 1;
            for (int i = 0; i < N; i++) {
                if (plants[i] != max_height) {
                    all_same = 0;
                    plants[i]++;
                }
            }
            if (all_same) {
                break;
            }
            days++;
        }
        printf("%d\n", days);
    }
    return 0;
}

