import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] plants = new int[N];
            for (int i = 0; i < N; i++) {
                plants[i] = scanner.nextInt();
            }
            int max_height = 0;
            for (int i = 0; i < N; i++) {
                if (plants[i] > max_height) {
                    max_height = plants[i];
                }
            }
            int days = 0;
            while (true) {
                int all_same = 1;
                for (int i = 0; i < N; i++) {
                    if (plants[i] != max_height) {
                        all_same = 0;
                        plants[i]++;
                    }
                }
                if (all_same) {
                    break;
                }
                days++;
            }
            System.out.println(days);
        }
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let T;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        T = parseInt(line);
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i > T) {
        readline.close();
        main();
    }
});
function main() {
    for (let i = 0; i < T; i++) {
        let N = input[i][0];
        let plants = input[i].slice(1);
        let max_height = Math.max(...plants);
        let days = 0;
        while (true) {
            let all_same = 1;
            for (let j = 0; j < N; j++) {
                if (plants[j] !== max_height) {
                    all_same = 0;
                    plants[j]++;
                }
            }
            if (all_same) {
                break;
            }
            days++;
        }
        console.log(days);
    }
}
